import itertools, math, torch
import torch.nn as nn

state=torch.load('/app/weights.pt', map_location='cpu')
data=torch.load('/app/dataset.pt', map_location='cpu')
src=data['src_sequences']
tgt=data['tgt_sequences']

class PositionalEncoding(nn.Module):
    def __init__(self, d_model, max_len=5000, batch_first=True):
        super().__init__()
        pe=torch.zeros(max_len,d_model)
        pos=torch.arange(0,max_len,dtype=torch.float32).unsqueeze(1)
        div=torch.exp(torch.arange(0,d_model,2,dtype=torch.float32)*(-math.log(10000.0)/d_model))
        pe[:,0::2]=torch.sin(pos*div)
        pe[:,1::2]=torch.cos(pos*div)
        if batch_first:
            pe=pe.unsqueeze(0)
        else:
            pe=pe.unsqueeze(1)
        self.register_buffer('pe',pe)
        self.batch_first=batch_first
    def forward(self,x):
        if self.batch_first:
            return x+self.pe[:,:x.size(1)]
        return x+self.pe[:x.size(0)]

class M(nn.Module):
    def __init__(self,batch_first=True,act='relu',pos_src=True,pos_tgt=True,nhead=8,norm_first=False):
        super().__init__()
        self.embedding=nn.Linear(64,128)
        self.pos_encoder=PositionalEncoding(128,5000,batch_first=batch_first)
        enc=nn.TransformerEncoderLayer(128,nhead,256,0.1,activation=act,batch_first=batch_first,norm_first=norm_first)
        self.transformer_encoder=nn.TransformerEncoder(enc,3)
        dec=nn.TransformerDecoderLayer(128,nhead,256,0.1,activation=act,batch_first=batch_first,norm_first=norm_first)
        self.transformer_decoder=nn.TransformerDecoder(dec,1)
        self.output_layer=nn.Linear(128,64)
        self.pos_src=pos_src
        self.pos_tgt=pos_tgt
        self.batch_first=batch_first
    def forward(self,src,tgt,causal=False):
        src=self.embedding(src)
        tgt=self.embedding(tgt)
        if self.pos_src:
            src=self.pos_encoder(src)
        if self.pos_tgt:
            tgt=self.pos_encoder(tgt)
        memory=self.transformer_encoder(src)
        if causal:
            if self.batch_first:
                L=tgt.size(1)
            else:
                L=tgt.size(0)
            m=torch.full((L,L),float('-inf'))
            m=torch.triu(m, diagonal=1)
        else:
            m=None
        out=self.transformer_decoder(tgt,memory,tgt_mask=m)
        return self.output_layer(out)

